const deal = $('Deal Invoice Sent Webhook').first().json;
const config = $('Get Config').first().json;
const props = deal.properties || deal;

const sku = props.selected_sku || props.deal_sku || props.sku || '';
const paymentLink = (sku && config?.stripe?.paymentLinksBySku?.[sku]) || config?.owner?.paymentLink || '';

return [{
  json: {
    clientName: props.dealname || props.name || '',
    dealId: deal.id || deal.dealId || '',
    amount: props.amount || 0,
    contactEmail: props.contact_email || props.email || '',
    contactFirstName: props.contact_firstname || props.firstName || '',
    contactPhone: props.contact_phone || props.phone || '',
    sku,
    paymentLink,
    config
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactEmail,
    subject: `Invoice reminder — ${d.clientName}`,
    html: `<p>Hi ${d.contactFirstName || 'there'},</p><p>Just a quick reminder that your invoice for $${d.amount} is due.</p><p><a href="${d.paymentLink}" style="display:inline-block;background:#3d8b8b;color:#fff;padding:12px 24px;text-decoration:none;border-radius:4px;">Pay Now</a></p><p>If you've already sent payment, please disregard this message.</p><p>— John<br/>${d.config.owner.companyName}</p>`,
    workflowName: 'SYS 03 — Invoice and Payment Collection'
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactPhone,
    body: `Hi ${d.contactFirstName || 'there'}, friendly reminder about your $${d.amount} invoice. Pay here: ${d.paymentLink} — John, IntraWeb`,
    workflowName: 'SYS 03 — Invoice and Payment Collection'
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactEmail,
    subject: `Payment overdue — ${d.clientName}`,
    html: `<p>Hi ${d.contactFirstName || 'there'},</p><p>Your invoice for $${d.amount} is now overdue. Please process payment at your earliest convenience.</p><p><a href="${d.paymentLink}">Pay Now</a></p><p>If there are any issues with the invoice or payment, reply to this email and we'll sort it out.</p><p>— John</p>`,
    workflowName: 'SYS 03 — Invoice and Payment Collection'
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    to: d.contactPhone,
    body: `Hi ${d.contactFirstName || 'there'}, your $${d.amount} invoice is overdue. Please process payment: ${d.paymentLink} — John, IntraWeb`,
    workflowName: 'SYS 03 — Invoice and Payment Collection'
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    message: `Invoice severely overdue (21 days): ${d.clientName} — $${d.amount}. Manual follow-up required.`,
    priority: 'error'
  }
}];

return [{
  json: {
    workflowName: 'SYS 03 — Invoice and Payment Collection',
    contactName: $('Extract Deal Data').first().json.clientName,
    phone: $('Extract Deal Data').first().json.contactPhone,
    eventType: 'invoice_sent',
    status: 'success',
    notes: `Amount: $${$('Extract Deal Data').first().json.amount}`
  }
}];

const d = $('Extract Deal Data').first().json;

return [{
  json: {
    message: `Payment received: ${d.clientName} — $${d.amount}`,
    priority: 'info'
  }
}];

